/**
 * VFX Assets - Celebration Spritesheet Data
 *
 * This file uses Vite's import system to bundle assets into the build.
 * Vite will automatically handle inlining or bundling as needed.
 */

// Import cashout animation spritesheet (Vite will bundle this)
import cashoutAnimationSprite from "../assets/cashout-animation.webp";

// Confetti spritesheet configuration (LOADED - Contains actual data)
export const CONFETTI_SPRITESHEET = {
  imageBase64:
    "data:image/webp;base64,",
  frameWidth: 270,
  frameHeight: 480,
  frameCount: 40,
  frameRate: 28,
};

// Cashout VFX spritesheet configuration (VITE BUNDLED - Monolithic HTML)
export const CASHOUT_SPRITESHEET = {
  imageUrl: cashoutAnimationSprite,
  frameWidth: 540,
  frameHeight: 960,
  frameCount: 28,
  frameRate: 28,
};

/**
 * Helper function to validate if confetti assets are loaded
 * Used by ConfettiManager to check if data is available
 *
 * @returns {Object} Validation status
 */
export function validateConfettiAssets() {
  const validation = {
    hasImage: CONFETTI_SPRITESHEET.imageBase64.length > 0,
    hasFrameWidth: CONFETTI_SPRITESHEET.frameWidth > 0,
    hasFrameHeight: CONFETTI_SPRITESHEET.frameHeight > 0,
  };

  validation.isComplete =
    validation.hasImage &&
    validation.hasFrameWidth &&
    validation.hasFrameHeight;

  validation.missingFields = [];
  if (!validation.hasImage) validation.missingFields.push("imageBase64");
  if (!validation.hasFrameWidth) validation.missingFields.push("frameWidth");
  if (!validation.hasFrameHeight) validation.missingFields.push("frameHeight");

  return validation;
}

/**
/**
 * Helper function to validate if cashout VFX assets are loaded
 * Used by CashoutVFXManager to check if data is available
 *
 * @returns {Object} Validation status
 */
export function validateCashoutAssets() {
  const validation = {
    hasImage:
      CASHOUT_SPRITESHEET.imageUrl && CASHOUT_SPRITESHEET.imageUrl.length > 0,
    hasFrameWidth: CASHOUT_SPRITESHEET.frameWidth > 0,
    hasFrameHeight: CASHOUT_SPRITESHEET.frameHeight > 0,
  };

  validation.isComplete =
    validation.hasImage &&
    validation.hasFrameWidth &&
    validation.hasFrameHeight;

  validation.missingFields = [];
  if (!validation.hasImage) validation.missingFields.push("imageUrl");
  if (!validation.hasFrameWidth) validation.missingFields.push("frameWidth");
  if (!validation.hasFrameHeight) validation.missingFields.push("frameHeight");

  return validation;
}

/**
 * Development/Debug: Log current asset status
 * Call this in console to check what's missing
 */
export function debugAssetStatus() {
  console.group("🎉 VFX Assets Status");

  const confettiValidation = validateConfettiAssets();
  console.log("\n🎊 Confetti:");
  console.log(
    "  Status:",
    confettiValidation.isComplete ? "✅ READY" : "❌ INCOMPLETE",
  );
  if (!confettiValidation.isComplete) {
    console.warn("  Missing:", confettiValidation.missingFields.join(", "));
  }

  const cashoutValidation = validateCashoutAssets();
  console.log("\n💰 Cashout VFX:");
  console.log(
    "  Status:",
    cashoutValidation.isComplete ? "✅ READY" : "❌ INCOMPLETE",
  );
  if (!cashoutValidation.isComplete) {
    console.warn("  Missing:", cashoutValidation.missingFields.join(", "));
  }

  console.groupEnd();

  return {
    confetti: confettiValidation,
    cashout: cashoutValidation,
  };
}
